import { normalizeOrderEvent, RawOrderEvent, Logger } from "./normalizeOrderEvent";

// ─── helpers ────────────────────────────────────────────────────────────────

function makeLogger(): { logger: Logger; warnings: string[] } {
  const warnings: string[] = [];
  const logger: Logger = { warn: (msg) => warnings.push(msg) };
  return { logger, warnings };
}

function makeRaw(overrides: Partial<RawOrderEvent> = {}): RawOrderEvent {
  return {
    id: "order-1",
    status: "PAID",
    total_amount: 1000,
    customer_name: "Alice",
    ...overrides,
  };
}

// ─── AC1: PAID → "completed" ─────────────────────────────────────────────────

describe("AC1: status PAID", () => {
  it('maps "PAID" to "completed"', () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ status: "PAID" }), logger);
    expect(result.status).toBe("completed");
  });
});

// ─── AC2: REFUNDED → "refunded" ──────────────────────────────────────────────

describe("AC2: status REFUNDED", () => {
  it('maps "REFUNDED" to "refunded"', () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ status: "REFUNDED" }), logger);
    expect(result.status).toBe("refunded");
  });
});

// ─── AC3: FAILED / DECLINED → "failed" ───────────────────────────────────────

describe("AC3: status FAILED or DECLINED", () => {
  it('maps "FAILED" to "failed"', () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ status: "FAILED" }), logger);
    expect(result.status).toBe("failed");
  });

  it('maps "DECLINED" to "failed"', () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ status: "DECLINED" }), logger);
    expect(result.status).toBe("failed");
  });
});

// ─── AC4: unknown status → "unknown" + warning ───────────────────────────────

describe("AC4: unknown status", () => {
  it('maps "PROCESSING" to "unknown"', () => {
    const { logger, warnings } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ status: "PROCESSING" }), logger);
    expect(result.status).toBe("unknown");
    expect(warnings).toHaveLength(1);
    expect(warnings[0]).toContain("PROCESSING");
  });

  it('maps an empty-string status to "unknown" and warns', () => {
    const { logger, warnings } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ status: "" }), logger);
    expect(result.status).toBe("unknown");
    expect(warnings).toHaveLength(1);
  });

  it('maps a lowercase "paid" to "unknown" (case-sensitive)', () => {
    const { logger, warnings } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ status: "paid" }), logger);
    expect(result.status).toBe("unknown");
    expect(warnings).toHaveLength(1);
  });

  it("does NOT warn for known statuses", () => {
    for (const status of ["PAID", "REFUNDED", "FAILED", "DECLINED"]) {
      const { logger, warnings } = makeLogger();
      normalizeOrderEvent(makeRaw({ status }), logger);
      expect(warnings).toHaveLength(0);
    }
  });
});

// ─── AC5: total_amount (cents) → amount (dollars, 2 dp) ──────────────────────

describe("AC5: cents-to-dollars conversion", () => {
  it("converts 1000 cents to 10.00 dollars", () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ total_amount: 1000 }), logger);
    expect(result.amount).toBe(10.00);
  });

  it("converts 199 cents to 1.99 dollars", () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ total_amount: 199 }), logger);
    expect(result.amount).toBe(1.99);
  });

  it("converts 0 cents to 0.00 dollars", () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ total_amount: 0 }), logger);
    expect(result.amount).toBe(0.00);
  });

  it("rounds to 2 decimal places (150 cents → 1.50)", () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ total_amount: 150 }), logger);
    expect(result.amount).toBe(1.50);
  });

  it("preserves the order id in the output", () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(makeRaw({ id: "order-99" }), logger);
    expect(result.id).toBe("order-99");
  });
});

// ─── AC6: missing / null customer_name → "Anonymous" ─────────────────────────

describe("AC6: missing or null customer_name", () => {
  it('uses "Anonymous" when customer_name is undefined', () => {
    const { logger } = makeLogger();
    const raw = makeRaw();
    delete (raw as any).customer_name;
    const result = normalizeOrderEvent(raw, logger);
    expect(result.customer_name).toBe("Anonymous");
  });

  it('uses "Anonymous" when customer_name is null', () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(
      makeRaw({ customer_name: null }),
      logger
    );
    expect(result.customer_name).toBe("Anonymous");
  });

  it("preserves a provided customer_name", () => {
    const { logger } = makeLogger();
    const result = normalizeOrderEvent(
      makeRaw({ customer_name: "Bob" }),
      logger
    );
    expect(result.customer_name).toBe("Bob");
  });
});

